:root {
  --bg-dark: #0f172a;
  --card-bg: rgba(30, 41, 59, 0.7);
  --accent: #38bdf8;
  --text-main: #f1f5f9;
  --text-muted: #94a3b8;
  --success: #10b981;
  --warning: #f59e0b;
  --info: #6366f1;
}

body {
  background: var(--bg-dark);
  font-family: "Inter", sans-serif;
  color: var(--text-main);
  margin: 0;
  padding: 15px;
}

.dashboard-container {
  max-width: 1200px;
  margin: 0 auto;
}

.header {
  margin-bottom: 25px;
}

.header h1 {
  font-size: 24px;
  margin: 0;
  font-weight: 700;
  background: linear-gradient(90deg, #fff, var(--text-muted));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.header p {
  color: var(--text-muted);
  margin: 5px 0 0 0;
  font-size: 14px;
}

.kpi-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 20px;
}

.kpi-card {
  background: var(--card-bg);
  backdrop-filter: blur(12px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  padding: 24px;
  border-radius: 16px;
  transition: transform 0.2s, border-color 0.2s;
}

.kpi-card:hover {
  transform: translateY(-4px);
  border-color: rgba(56, 189, 248, 0.4);
}

.kpi-card.highlight {
  border-left: 4px solid var(--accent);
}

.icon {
  font-size: 24px;
  margin-bottom: 12px;
}

.label {
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: var(--text-muted);
  margin-bottom: 8px;
}

.value {
  font-size: 28px;
  font-weight: 800;
  margin-bottom: 4px;
}

.value.success {
  color: var(--success);
}

.value.warning {
  color: var(--warning);
}

.value.info {
  color: var(--info);
}

.sub-label {
  font-size: 12px;
  color: rgba(148, 163, 184, 0.6);
}

