appsmith.onReady(() => {
  const data = appsmith.model.salaryBatch || [];
  let totalNet = 0;
  let totalDeductions = 0;
  let totalLiabilities = 0;
  let totalAdjustments = 0;
  data.forEach(emp => {
    totalNet += parseFloat(emp.net_salary || 0);
    totalDeductions += parseFloat(emp.total_deductions || 0);
    totalLiabilities += parseFloat(emp.misc_liabilities || 0);

    // Savings = Base Salary - Adjusted Base Salary
    const savings = parseFloat(emp.base_salary || 0) - parseFloat(emp.adjusted_base_salary || 0);
    totalAdjustments += Math.max(0, savings);
  });
  const formatCurrency = val => "₹" + val.toLocaleString('en-IN', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
  document.getElementById('total-net').innerText = formatCurrency(totalNet);
  document.getElementById('total-deductions').innerText = formatCurrency(totalDeductions);
  document.getElementById('total-liabilities').innerText = formatCurrency(totalLiabilities);
  document.getElementById('total-adjustments').innerText = formatCurrency(totalAdjustments);
  document.getElementById('employee-count').innerText = `Summarizing ${data.length} Employees in this Batch`;
});

